let d = msg.payload;
if (!d) return [null, null, null];

// 各區時長／次數：直接讀取 Python 端（plugins/lick_stage/models.py）算好的數值。
// 佔比％（xxx_pct、best_pct）也已在 Python 端算好，Node-RED 這裡只負責組裝成
// Dashboard 要的資料結構，不重複做除法／加總（運算模組化：Python 算，Node 顯示）。
let times = {
    BODY: parseFloat(d.body_time || 0),
    FL:   parseFloat(d.fl_time   || 0),
    FR:   parseFloat(d.fr_time   || 0),
    HL:   parseFloat(d.hl_time   || 0),
    HR:   parseFloat(d.hr_time   || 0)
};
let hits = {
    BODY: parseInt(d.body_hits || 0),
    FL:   parseInt(d.fl_hits   || 0),
    FR:   parseInt(d.fr_hits   || 0),
    HL:   parseInt(d.hl_hits   || 0),
    HR:   parseInt(d.hr_hits   || 0)
};
let pcts = {
    BODY: (d.body_pct != null) ? parseFloat(d.body_pct) : NaN,
    FL:   (d.fl_pct   != null) ? parseFloat(d.fl_pct)   : NaN,
    FR:   (d.fr_pct   != null) ? parseFloat(d.fr_pct)   : NaN,
    HL:   (d.hl_pct   != null) ? parseFloat(d.hl_pct)   : NaN,
    HR:   (d.hr_pct   != null) ? parseFloat(d.hr_pct)   : NaN
};

let zones = {};
['BODY','FL','FR','HL','HR'].forEach(function(k){
    let t=times[k], h=hits[k];
    zones[k]={
        hits:        h,
        time_sec:    t,
        pref_pct:    pcts[k],
        sec_per_hit: h>0 ? t/h : NaN
    };
});

// best_zone／best_pct 皆由 Python 端算好並送出，Node 端直接讀取，不重算
let best_zone = d.best_zone || 'NO_TARGET';
let best_pct  = (d.best_pct != null) ? parseFloat(d.best_pct) : null;

function nf(v){return (v!=null&&v!==undefined)?parseFloat(v):NaN;}

let out = {
    zones,
    best_zone,
    best_pct,
    total_lick_time:    nf(d.total_lick_time),
    current_zone:       d.current_zone  || 'NO_TARGET',
    nearest_label:      d.current_zone  || 'NO_TARGET',
    nearest_t:          NaN,
    nose_detected:      d.valid ? 1 : 0,
    face_state:         d.face_state    || 'UNKNOWN',
    state_stability:    nf(d.state_stability),
    distance_px:        nf(d.dist_px),
    distance_norm:      nf(d.dist_norm),
    gaze_forward_norm:  nf(d.gaze_fwd),
    gaze_lateral_norm:  nf(d.gaze_lat),
    gaze_angle_deg:     nf(d.gaze_angle),
    lick_axis_score:    NaN,
    lick_lateral_score: NaN,
    valid:              d.valid ? 1 : 0,
    frame:              parseInt(d.frame    || 0),
    time_sec:           nf(d.time_sec),
    video_path:         '',
    trap_pts:           d.trap_pts || [],
    nose_xy:            d.nose_xy || []
};

global.set('lick_s2_latest', out);
msg.payload = out;
return [msg, msg, msg];

let ip = null;
try {
    ip = (msg.payload && msg.payload.ip) ? msg.payload.ip : (global.get('lick_python_ip', 'file') || global.get('lick_python_ip') || null);
} catch (e) {
    ip = (msg.payload && msg.payload.ip) ? msg.payload.ip : (global.get('lick_python_ip') || null);
}
if (ip) {
    try {
        global.set('lick_python_ip', ip, 'file');
    } catch (e) {
        global.set('lick_python_ip', ip);
    }
}
msg.payload = { ip: ip };
msg.stream_url = ip ? `http://${ip}:5000/stream` : '';
node.warn('lick_python_online received IP: ' + (ip || 'null'));
return msg;

let ip = null;
try {
    ip = global.get('lick_python_ip', 'file') || global.get('lick_python_ip') || null;
} catch (e) {
    ip = global.get('lick_python_ip') || null;
}
if (!ip) return null;
msg.payload = { ip: ip };
msg.stream_url = `http://${ip}:5000/stream`;
return msg;

let d = msg.payload;
if (!d) return null;
global.set('ext_zone_latest', d);
msg.payload = d;
return msg;

