try {
    ip = global.get('lick_python_ip', 'file') || global.get('lick_python_ip') || null;
} catch (e) {
    ip = global.get('lick_python_ip') || null;
}
if (!ip) return null;
msg.payload = { ip: ip };
msg.stream_url = `http://${ip}:5000/stream`;
